# conftest.py
import pytest
from fastapi import FastAPI, Depends
from fastapi.testclient import TestClient
from sqlalchemy import create_engine, String
from sqlalchemy.orm import (
    DeclarativeBase, Mapped, mapped_column, Session, sessionmaker
)
from sqlalchemy.pool import StaticPool
from typing import Annotated

# --- App and models ---
class Base(DeclarativeBase): pass

class Item(Base):
    __tablename__ = "items"
    id: Mapped[int] = mapped_column(primary_key=True)
    name: Mapped[str] = mapped_column(String(100))

def get_db():
    raise NotImplementedError("Override in tests")  # never called in tests

DbDep = Annotated[Session, Depends(get_db)]

def create_app() -> FastAPI:
    app = FastAPI()

    @app.post("/items", status_code=201)
    def create_item(name: str, db: DbDep):
        item = Item(name=name)
        db.add(item)
        db.commit()
        db.refresh(item)
        return {"id": item.id, "name": item.name}

    @app.get("/items")
    def list_items(db: DbDep):
        return db.query(Item).all()

    return app

# --- Fixtures ---
@pytest.fixture(scope="session")
def engine():
    """Single in-memory engine for all tests."""
    return create_engine(
        "sqlite:///:memory:",
        connect_args={"check_same_thread": False},
        poolclass=StaticPool,
    )

@pytest.fixture(scope="session")
def tables(engine):
    """Create tables once for the test session."""
    Base.metadata.create_all(engine)
    yield
    Base.metadata.drop_all(engine)

@pytest.fixture
def db(engine, tables):
    """Fresh session with rollback after each test."""
    connection = engine.connect()
    transaction = connection.begin()
    session = Session(connection)
    yield session
    session.close()
    transaction.rollback()
    connection.close()

@pytest.fixture
def app():
    return create_app()

@pytest.fixture
def client(app, db):
    """TestClient with overridden DB dependency."""
    def override_get_db():
        yield db

    app.dependency_overrides[get_db] = override_get_db
    with TestClient(app) as c:
        yield c
    app.dependency_overrides.clear()

@pytest.fixture
def sample_item(db):
    """Pre-create test data."""
    item = Item(name="Test Item")
    db.add(item)
    db.commit()
    db.refresh(item)
    return item

# --- Example tests ---
def test_create_item(client):
    response = client.post("/items?name=Widget")
    assert response.status_code == 201
    assert response.json()["name"] == "Widget"

def test_list_items(client, sample_item):
    response = client.get("/items")
    assert response.status_code == 200
    assert len(response.json()) == 1

def test_isolation(client):
    """Previous test's data is rolled back."""
    response = client.get("/items")
    assert response.status_code == 200
    assert len(response.json()) == 0  # clean slate

print("Fixtures demonstrated")

