from fastapi import FastAPI, Depends, HTTPException
from fastapi.testclient import TestClient
from pydantic import BaseModel
from typing import Annotated

app = FastAPI()

# --- Production dependencies ---
class User(BaseModel):
    id: int
    username: str
    is_admin: bool = False

def get_current_user() -> User:
    """In production, this validates JWT tokens."""
    raise HTTPException(status_code=401, detail="Not authenticated")

def get_admin_user(
    user: Annotated[User, Depends(get_current_user)],
) -> User:
    if not user.is_admin:
        raise HTTPException(status_code=403, detail="Not an admin")
    return user

UserDep = Annotated[User, Depends(get_current_user)]
AdminDep = Annotated[User, Depends(get_admin_user)]

@app.get("/profile")
def profile(user: UserDep):
    return {"username": user.username}

@app.get("/admin/dashboard")
def admin_dashboard(admin: AdminDep):
    return {"message": f"Welcome admin {admin.username}"}

@app.get("/public")
def public():
    return {"message": "no auth needed"}

# --- Tests with overrides ---

# Override: regular user
def mock_regular_user() -> User:
    return User(id=1, username="testuser", is_admin=False)

# Override: admin user
def mock_admin_user() -> User:
    return User(id=99, username="admin", is_admin=True)

# Test 1: Authenticated user
app.dependency_overrides[get_current_user] = mock_regular_user
client = TestClient(app)
response = client.get("/profile")
print(f"Profile: {response.status_code} {response.json()}")

# Test 2: Non-admin accessing admin route
response = client.get("/admin/dashboard")
print(f"Admin (non-admin user): {response.status_code}")

# Test 3: Admin user
app.dependency_overrides[get_current_user] = mock_admin_user
response = client.get("/admin/dashboard")
print(f"Admin (admin user): {response.status_code} {response.json()}")

# Test 4: Public endpoint (no override needed)
response = client.get("/public")
print(f"Public: {response.status_code}")

# Always clean up
app.dependency_overrides.clear()

# Expected Output:
# Profile: 200 {'username': 'testuser'}
# Admin (non-admin user): 403
# Admin (admin user): 200 {'message': 'Welcome admin admin'}
# Public: 200

